const requireSerial = env.get('require_serial') === 'true';
const requireMac = env.get('require_mac') === 'true';
const defaultMode = env.get('default_mode');

const input = msg.payload || {};
const product = input.product;
const serial = input.serial_no || '';
const mac = input.mac_id || '';
const mode = input.mode || defaultMode;

const errors = [];
if (!product) errors.push('product is required');
if (requireSerial && !serial) errors.push('serial_no is required');
if (requireMac && !mac) errors.push('mac_id is required');
if (!['mock-pass', 'mock-fail', 'mock-random', 'real'].includes(mode)) {
    errors.push(`invalid mode: ${mode}`);
}

if (errors.length > 0) {
    msg.payload = {
        start_cycle: false,
        errors,
        timestamp: new Date().toISOString()
    };
} else {
    msg.payload = {
        start_cycle: true,
        product,
        serial_no: serial,
        mac_id: mac,
        mode,
        timestamp: new Date().toISOString()
    };
}
return msg;
